function magazynDokumentKodPorownawczy(value=""){const raw=String(value||"").trim().toLowerCase().replace(/\s+/g,"");const digits=raw.replace(/\D/g,"").replace(/^0+(?=\d)/,"");return {raw,digits};}
function magazynDokumentProduktPoOdczycie(parsed={}){
  const products=typeof produktyDoAdministracji==="function"?produktyDoAdministracji():[];
  if(parsed.productId)return products.find(product=>String(product.id)===String(parsed.productId))||null;
  const wanted=magazynDokumentKodPorownawczy(parsed.scanCode||parsed.raw||"");if(!wanted.raw)return null;
  return products.find(product=>[product.gtin,product.ean,product.externalId,product.sku,product.kodProducenta,product.mpn,product.kodKreskowy].some(value=>{const candidate=magazynDokumentKodPorownawczy(value);return candidate.raw&&candidate.raw===wanted.raw||wanted.digits.length>=6&&candidate.digits===wanted.digits;}))||null;
}
