async function magazynDokumentDodajKod(documentId,code,quantity=1,fromCamera=false){
  const parsed=typeof magazynQRParsujOdczyt==="function"?magazynQRParsujOdczyt(code):{type:"code",scanCode:String(code||"").trim()};
  if(parsed.type==="location"){magazynDokumentUstawLokalizacjeSkanu(documentId,parsed.code,{fromCamera});return true;}
  const session=magazynDokumentSkanSesja(documentId);if(session.busy){magazynDokumentSkanStatus("Trwa zatwierdzanie poprzedniej pozycji — poczekaj chwilę.");return false;}
  if(!session.confirmedLocation||session.proposedLocation){magazynDokumentSkanStatus("Najpierw zeskanuj lub wybierz półkę i naciśnij „Potwierdź półkę”.");toast("Najpierw potwierdź półkę");return false;}
  if(session.pending){const saved=await magazynDokumentZatwierdzBiezacaPozycje(documentId,{automatic:true});if(!saved)return false;quantity=1;}
  const product=magazynDokumentProduktPoOdczycie(parsed),raw=String(parsed.scanCode||parsed.raw||code||"").trim();session.pending={productId:product?.id||(parsed.type==="product"?parsed.productId:""),code:raw,name:product?.nazwa||`Kod ${raw}`,image:product?.zdjecie||"",ean:product?.gtin||product?.ean||raw,externalId:product?.externalId||product?.sku||"",quantity:Math.max(1,Number(quantity)||1),fromCamera};magazynDokumentKamera.quantity=session.pending.quantity;
  magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus(`Rozpoznano ${session.pending.name}. Ustaw ilość i zatwierdź albo zeskanuj następny produkt.`);return true;
}
