function magazynDokumentWalidacja(doc){
  const lines=Array.isArray(doc?.lines)?doc.lines:[],hasDictionary=magazynDokumentPolkiDoWyboru().length>0,issues=[];let missingLocations=0,stockProblems=0,readyLines=0,total=0;
  lines.forEach(line=>{const quantity=Math.max(0,Number(line.quantity)||0),stock=stanMagazynuId(line.productId),shelf=magazynDokumentPolkaLokalizacji(line.location),lineIssues=[];total+=quantity;if(quantity<1)lineIssues.push("Podaj ilość większą od zera");if(hasDictionary&&!shelf){lineIssues.push("Wybierz aktywną półkę");missingLocations++;}if(doc.type==="WZ"&&stock===null){lineIssues.push("Brak kontrolowanego stanu");stockProblems++;}else if(doc.type==="WZ"&&stock<quantity){lineIssues.push(`Dostępne ${stock}, wymagane ${quantity}`);stockProblems++;}if(lineIssues.length)issues.push({productId:String(line.productId),name:line.name||`Produkt ${line.productId}`,messages:lineIssues});else readyLines++;});
  if(!lines.length)issues.push({productId:"",name:"Dokument",messages:["Dodaj co najmniej jedną pozycję"]});
  return {ready:lines.length>0&&!issues.length,issues,missingLocations,stockProblems,readyLines,total,lineCount:lines.length};
}
