    let nativeFormats=[],nativeDetector=false,zxingReady=false;
    if(typeof BarcodeDetector!=="undefined"){try{nativeFormats=await BarcodeDetector.getSupportedFormats();nativeDetector=nativeFormats.includes("ean_13")&&nativeFormats.includes("qr_code");}catch(error){nativeDetector=false;}}
