  try{if(video?.readyState>=2&&!magazynDokumentKamera.busy&&!magazynDokumentKamera.minimized){magazynDokumentKamera.busy=true;const detected=magazynDokumentKamera.detector?await magazynDokumentKamera.detector.detect(video):[],code=magazynDokumentKamera.detector?String(detected?.[0]?.rawValue||"").trim():magazynQROdczytajZVideo(video,magazynDokumentKamera);if(code)magazynDokumentKameraObsluzOdczyt(code);else magazynDokumentKameraZwolnijPowtorzenie();magazynDokumentKamera.busy=false;}}
