  assign("gtin",auto.gtin||auto.ean||(catalog.eans||[])[0]||p.gtin||p.ean);
  assign("ean",auto.ean||auto.gtin||(catalog.eans||[])[0]||p.ean||p.gtin);
  assign("kodProducenta",auto.kodProducenta||auto.mpn||p.kodProducenta||p.mpn);
